VALUES
  ('optometrist-moex-03004', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關驗配鞏膜隱形眼鏡，下列敘述何者錯誤？', '["配戴一段時間後，鏡片會沉降（settle）至結膜表面後，此時中央矢深（sagittal depth）減少約150μm", "驗配完成時，中央矢深一般不宜低於100～200μm", "驗配過程中，輪部淨空（limbal clearance）若無法達成，則需縮小鏡片尺寸", "在插片驗光時，對於視力表現未如預期者，可以嘗試柱狀鏡設計來矯正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f85cd30c1fda", "answer_pdf_sha1": "2c2bddf06560", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
